class DSU {
    constructor(n) {
        this.parent = new Array(n + 1);
        this.onlineSets = new Array(n + 1);
        for (let i = 1; i <= n; ++i) {
            this.parent[i] = i;
            this.onlineSets[i] = new Set();
            this.onlineSets[i].add(i);
        }
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    unite(u, v) {
        const pu = this.find(u);
        const pv = this.find(v);
        if (pu !== pv) {
            if (this.onlineSets[pu].size < this.onlineSets[pv].size) {
                [pu, pv] = [pv, pu];
            }
            this.parent[pv] = pu;
            for (const elem of this.onlineSets[pv]) {
                this.onlineSets[pu].add(elem);
            }
            this.onlineSets[pv].clear();
        }
    }
}

function solve(c, connections, queries) {
    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.unite(u, v);
    }

    const online = new Array(c + 1).fill(true);
    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                if (dsu.onlineSets[root].size === 0) {
                    result.push(-1);
                } else {
                    const minId = Math.min(...dsu.onlineSets[root]);
                    result.push(minId);
                }
            }
        } else if (type === 2) {
            if (online[x]) {
                online[x] = false;
                const root = dsu.find(x);
                dsu.onlineSets[root].delete(x);
            }
        }
    }

    return result;
}
