#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

struct DSU {
    vector<long long> parent;
    vector<set<long long>> online_sets;

    DSU(long long n) : parent(n + 1), online_sets(n + 1) {
        for (long long i = 1; i <= n; ++i) {
            parent[i] = i;
            online_sets[i].insert(i);
        }
    }

    long long find(long long u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    void unite(long long u, long long v) {
        long long pu = find(u);
        long long pv = find(v);
        if (pu != pv) {
            if (online_sets[pu].size() < online_sets[pv].size()) {
                swap(pu, pv);
            }
            parent[pv] = pu;
            online_sets[pu].insert(online_sets[pv].begin(), online_sets[pv].end());
            online_sets[pv].clear();
        }
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    DSU dsu(c);
    for (const auto& conn : connections) {
        dsu.unite(conn[0], conn[1]);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = dsu.find(x);
                if (dsu.online_sets[root].empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*dsu.online_sets[root].begin());
                }
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                long long root = dsu.find(x);
                dsu.online_sets[root].erase(x);
            }
        }
    }

    return result;
}

